// Log de eventos saltados
const data = $('🔀 Merge Results').first().json;

return [{
  json: {
    status: 'SKIPPED',
    reason: data.validation?.isCancellation ? 'CANCELLED_EVENT' : 'INVALID_EMAIL',
    email: data.lead?.email || 'unknown',
    name: data.lead?.name || 'unknown',
    subject: data.debug?.rawSubject || 'unknown',
    timestamp: new Date().toISOString()
  }
}];

const input = $input.first().json;
const body = input.body || input;

function sanitize(str) {
  if (!str || typeof str !== 'string') return '';
  return str.trim().replace(/<[^>]*>/g, '').replace(/[<>'"]/g, '').substring(0, 500);
}

function validateEmail(email) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

function normalizeRevenue(value) {
  const v = (value || '').toLowerCase();
  if (v.includes('50k') || v.includes('+50')) return { label: '50k+', score: 40 };
  if (v.includes('10k')) return { label: '10k-50k', score: 20 };
  if (v.includes('2k')) return { label: '2k-10k', score: 10 };
  return { label: '0-2k', score: 0 };
}

function normalizeTeam(value) {
  const v = (value || '').toLowerCase();
  if (v.includes('10+') || v.includes('más de 10')) return { size: 15, score: 30 };
  if (v.includes('4') || v.includes('4-10')) return { size: 7, score: 20 };
  if (v.includes('1') || v.includes('1-3')) return { size: 2, score: 10 };
  return { size: 0, score: 0 };
}

function normalizeBudget(value) {
  const v = (value || '').toLowerCase();
  if (v.includes('sí') || v.includes('si')) return { ready: true, score: 30 };
  if (v.includes('posible')) return { ready: 'maybe', score: 10 };
  return { ready: false, score: -20 };
}

function normalizeUrgency(value) {
  const v = (value || '').toLowerCase();
  if (v.includes('inmediato') || v.includes('ya')) return { level: 'Inmediato', score: 20 };
  if (v.includes('30')) return { level: '30 días', score: 10 };
  return { level: '90 días', score: 0 };
}

const leadId = sanitize(body.leadId);
const email = sanitize(body.email)?.toLowerCase();
const fullName = sanitize(body.fullName);
const timestamp = new Date().toISOString();

const fields = {
  fullName: fullName,
  email: email,
  mainChannel: sanitize(body.mainChannel || ''),
  channelUsername: sanitize(body.channelUsername || ''),
  monthlyRevenue: sanitize(body.monthlyRevenue || ''),
  teamSize: sanitize(body.teamSize || ''),
  techInvestment: sanitize(body.techInvestment || ''),
  mainPain: sanitize(body.mainPain || ''),
  budget5k: sanitize(body.budget5k || ''),
  urgency: sanitize(body.urgency || ''),
  additionalInfo: sanitize(body.additionalInfo || '')
};

const answeredFields = Object.values(fields).filter(v => v && v.length > 0).length;
const totalFields = 11;
const percentComplete = Math.round((answeredFields / totalFields) * 100);

const errors = [];
if (!fullName) errors.push('nombre requerido');
if (!email || !validateEmail(email)) errors.push('email inválido');
if (answeredFields < 5) errors.push('muy pocas respuestas');

const normalized = {
  revenue: normalizeRevenue(fields.monthlyRevenue),
  team: normalizeTeam(fields.teamSize),
  budget: normalizeBudget(fields.budget5k),
  urgency: normalizeUrgency(fields.urgency)
};

const output = {
  isValid: errors.length === 0,
  errors: errors,
  leadId: leadId,
  email: email,
  fullName: fullName,
  completionTimestamp: timestamp,
  percentComplete: percentComplete,
  raw: fields,
  normalized: normalized,
  scoringInput: {
    completionScore: percentComplete,
    revenueScore: normalized.revenue.score,
    teamScore: normalized.team.score,
    budgetScore: normalized.budget.score,
    urgencyScore: normalized.urgency.score
  }
};

return [{ json: output }];

const protocolData = $('Protocol Validator1').item.json;
const scoringInput = protocolData.scoringInput;
const raw = protocolData.raw;

// ========================================
// CONFIGURACIÓN ULTRA AVANZADA
// ========================================
const CONFIG = {
  thresholds: { 
    HIGH_VALUE: 78,    // Más estricto
    READY: 62, 
    WARM: 42, 
    COLD: 0 
  },
  weights: { 
    completion: 1.0, 
    budget: 1.5,           // Mayor peso
    revenue: 1.2, 
    team: 0.9, 
    urgency: 1.1, 
    engagement: 0.6,
    painQuality: 2.0,      // PESO MÁXIMO
    consistency: 1.3,      // NUEVO
    maturity: 1.0,         // NUEVO
    commitment: 1.2        // NUEVO
  },
  penalties: { 
    incompleteProtocol: -8,
    genericPain: -50,           
    tooShortPain: -35,          
    inconsistentProfile: -30,   
    noUrgency: -20,             
    fakeBudget: -45,
    copyPaste: -40,             // NUEVO
    lowCommitment: -25,         // NUEVO
    immatureProfile: -20,       // NUEVO
    evasiveAnswers: -30,        // NUEVO
    curiositySeeker: -60        // NUEVO: turista
  },
  bonuses: {
    ultraSpecific: 40,          // NUEVO
    urgentAndSerious: 35,       // NUEVO
    provenRevenue: 30,          // NUEVO
    teamReady: 25,              // NUEVO
    techSavvy: 20               // NUEVO
  }
};

// ========================================
// 1. ANÁLISIS ULTRA PROFUNDO DEL DOLOR
// ========================================
function analyzePainQualityUltra(painText, additionalInfo) {
  if (!painText || typeof painText !== 'string') {
    return { 
      score: -40, 
      flags: ['no_pain'], 
      quality: 'invalid',
      sentiment: 'none',
      specificity: 0
    };
  }

  const text = painText.toLowerCase().trim();
  const additional = (additionalInfo || '').toLowerCase().trim();
  const combined = text + ' ' + additional;

  const length = text.length;
  const wordCount = text.split(/\s+/).length;

  let score = 0;
  let flags = [];
  let specificity = 0;

  // ============ LONGITUD INTELIGENTE ============
  if (length < 10) {
    flags.push('extremely_short');
    score -= 50; // Casi descalifica
  } else if (length < 20) {
    flags.push('too_short');
    score -= 35;
  } else if (length < 40) {
    score -= 10;
  } else if (length >= 50 && length <= 300) {
    score += 30; // Sweet spot
    specificity += 20;
  } else if (length > 300) {
    score += 15; // Bueno pero puede ser relleno
  }

  // ============ DETECTOR DE COPY-PASTE ============
  // Frases que parecen copiadas de blogs/ChatGPT
  const copyPastePatterns = [
    'en el competitivo mundo de',
    'en la era digital',
    'maximizar el potencial',
    'optimizar los recursos',
    'implementar estrategias',
    'revolucionar la industria',
    'transformación digital',
    'sinergia entre equipos',
    'alinear objetivos'
  ];

  let copyPasteCount = 0;
  copyPastePatterns.forEach(pattern => {
    if (combined.includes(pattern)) copyPasteCount++;
  });

  if (copyPasteCount >= 2) {
    flags.push('copy_paste_detected');
    score -= 40;
  }

  // ============ PALABRAS GENÉRICAS (EXPANDIDO) ============
  const genericPhrases = [
    // Vagas
    'no sé', 'nose', 'nada', 'todo bien', 'normal', 'regular',
    'por ahí', 'algo', 'cosas', 'esto', 'eso', 'lo típico',
    'problemas normales', 'nada grave', 'no mucho', 'más o menos',

    // Desires sin pain real
    'quiero crecer', 'necesito clientes', 'quiero escalar',
    'quiero más ventas', 'necesito ayuda', 'busco soluciones',
    'mejorar mi negocio', 'hacer más dinero',

    // Test/Fake
    'test', 'prueba', 'testing', 'ejemplo', 'asdf', 'xxx', 'aaa',
    'solo viendo', 'curiosidad', 'ver qué tal', 'probar',

    // Evasivas
    'varios temas', 'muchas cosas', 'todo un poco', 'depende'
  ];

  let genericCount = 0;
  genericPhrases.forEach(phrase => {
    if (text.includes(phrase)) genericCount++;
  });

  if (genericCount >= 3) {
    flags.push('highly_generic');
    score -= 50;
  } else if (genericCount >= 2) {
    flags.push('generic_response');
    score -= 30;
  } else if (genericCount === 1) {
    score -= 10;
  }

  // ============ PALABRAS ULTRA ESPECÍFICAS (EXPANDIDO) ============
  const painCategories = {
    tiempo: {
      words: ['horas', 'tiempo', 'demora', 'lento', 'manual', 'repetitivo', 'diario', 'semana', 'mes'],
      weight: 15
    },
    escala: {
      words: ['escalar', 'crecer', 'limita', 'tope', 'capacidad', 'cuello de botella', 'no puedo más', 'saturado'],
      weight: 18
    },
    equipo: {
      words: ['equipo', 'delegar', 'depende de mí', 'solo yo', 'contratar', 'burnout', 'agotado', 'sobrecargado'],
      weight: 16
    },
    sistemas: {
      words: ['desorganizado', 'caos', 'perdemos', 'errores', 'fallas', 'bugs', 'se cae', 'no funciona'],
      weight: 14
    },
    financiero: {
      words: ['ingresos', 'ventas', 'conversión', 'leads', 'clientes', 'facturación', 'revenue', 'mrr', 'arr'],
      weight: 20
    },
    emocional: {
      words: ['frustrado', 'estancado', 'no puedo', 'imposible', 'difícil', 'estresado', 'desesperado'],
      weight: 12
    },
    técnico: {
      words: ['crm', 'automatización', 'integración', 'api', 'webhook', 'workflow', 'software', 'plataforma'],
      weight: 25 // BONUS: sabe de tech
    }
  };

  let categoryScores = {};
  let totalSpecificWords = 0;

  Object.keys(painCategories).forEach(category => {
    let count = 0;
    painCategories[category].words.forEach(word => {
      if (combined.includes(word)) count++;
    });
    if (count > 0) {
      categoryScores[category] = count;
      totalSpecificWords += count;
      score += count * painCategories[category].weight;
      specificity += count * 10;
    }
  });

  if (totalSpecificWords >= 5) {
    flags.push('ultra_specific');
    score += 40; // BONUS MASIVO
  } else if (totalSpecificWords >= 3) {
    flags.push('specific');
    score += 25;
  } else if (totalSpecificWords < 2) {
    flags.push('lacks_specificity');
    score -= 20;
  }

  // ============ CUANTIFICACIÓN (números = seriedad) ============
  const numberMatches = text.match(/\d+/g);
  const numberCount = numberMatches ? numberMatches.length : 0;

  if (numberCount >= 3) {
    score += 25; // Cuantifica todo
    specificity += 15;
  } else if (numberCount >= 1) {
    score += 15;
    specificity += 10;
  }

  // ============ ESTRUCTURA Y EJEMPLOS ============
  const hasExamples = 
    text.includes('por ejemplo') || 
    text.includes('ej:') || 
    text.includes('como') ||
    text.includes('actualmente') ||
    text.includes('ahora mismo');

  if (hasExamples) {
    score += 20;
    specificity += 10;
  }

  // Uso de conectores (coherencia)
  const connectors = ['porque', 'entonces', 'además', 'también', 'pero', 'sin embargo'];
  let connectorCount = 0;
  connectors.forEach(conn => {
    if (text.includes(conn)) connectorCount++;
  });

  if (connectorCount >= 2) {
    score += 15; // Piensa estructurado
  }

  // ============ ANÁLISIS DE SENTIMIENTO ============
  const urgencyWords = ['urgente', 'ya', 'ahora', 'pronto', 'rápido', 'inmediato', 'necesito', 'desesperado'];
  const frustrationWords = ['frustrado', 'harto', 'cansado', 'no aguanto', 'agotado'];
  const actionWords = ['implementar', 'resolver', 'solucionar', 'arreglar', 'mejorar'];

  let sentiment = 'neutral';
  let urgencyLevel = 0;

  urgencyWords.forEach(word => {
    if (combined.includes(word)) urgencyLevel++;
  });

  if (urgencyLevel >= 2) {
    sentiment = 'urgent';
    score += 20;
  }

  frustrationWords.forEach(word => {
    if (combined.includes(word)) {
      sentiment = 'frustrated';
      score += 15; // Pain real
    }
  });

  actionWords.forEach(word => {
    if (combined.includes(word)) {
      score += 10; // Oriented to action
    }
  });

  // ============ DETECTOR DE TURISTA (curiosity seeker) ============
  const touristPhrases = [
    'solo viendo', 'ver opciones', 'investigando', 'comparando',
    'todavía no sé', 'evaluando', 'explorando', 'ver qué hay',
    'curiosidad', 'interesado pero', 'tal vez', 'quizás'
  ];

  let touristCount = 0;
  touristPhrases.forEach(phrase => {
    if (combined.includes(phrase)) touristCount++;
  });

  if (touristCount >= 2) {
    flags.push('curiosity_seeker');
    score -= 60; // PENALIZACIÓN BRUTAL
  }

  // ============ CLASIFICACIÓN FINAL ============
  let quality = 'low';
  if (score >= 60 && specificity >= 40) quality = 'ultra_high';
  else if (score >= 40) quality = 'high';
  else if (score >= 15) quality = 'medium';

  return { 
    score, 
    flags, 
    quality,
    sentiment,
    specificity,
    length, 
    wordCount, 
    specificWords: totalSpecificWords,
    genericWords: genericCount,
    numberCount,
    categoryScores
  };
}

// ========================================
// 2. ANÁLISIS DE COHERENCIA ULTRA AVANZADO
// ========================================
function analyzeProfileConsistencyUltra(data) {
  let flags = [];
  let penalty = 0;
  let consistencyScore = 100;

  const revenue = (data.monthlyRevenue || '').toLowerCase();
  const team = (data.teamSize || '').toLowerCase();
  const budget = (data.budget5k || '').toLowerCase();
  const techInvestment = (data.techInvestment || '').toLowerCase();
  const urgency = (data.urgency || '').toLowerCase();
  const channel = (data.mainChannel || '').toLowerCase();

  // ============ VALIDACIONES CRUZADAS ============

  // 1. Revenue vs Team
  if ((revenue.includes('50k') || revenue.includes('10k-50k')) && team.includes('solo')) {
    flags.push('impossible_solo_revenue');
    penalty -= 35; // Muy sospechoso
    consistencyScore -= 40;
  }

  if (revenue.includes('0-2k') && (team.includes('10+') || team.includes('4-10'))) {
    flags.push('unsustainable_team_size');
    penalty -= 30;
    consistencyScore -= 35;
  }

  // 2. Revenue vs Budget
  if ((revenue.includes('50k') || revenue.includes('10k-50k')) && budget.includes('no')) {
    flags.push('high_revenue_no_investment');
    penalty -= 25;
    consistencyScore -= 30;
  }

  if (revenue.includes('0-2k') && budget.includes('sí')) {
    // Puede ser válido (va a invertir todo) pero riesgoso
    flags.push('low_revenue_high_commitment');
    penalty -= 10; // Pequeña penalización
  }

  // 3. Tech Investment History
  if (techInvestment.includes('no') && budget.includes('sí')) {
    flags.push('first_time_investor'); // No es malo, pero watch out
    consistencyScore -= 10;
  }

  if (techInvestment.includes('sí') && budget.includes('no')) {
    flags.push('invested_before_but_broke'); // Red flag
    penalty -= 20;
    consistencyScore -= 25;
  }

  // 4. Urgency vs Budget
  if (urgency.includes('inmediato') && budget.includes('no')) {
    flags.push('urgent_but_no_money');
    penalty -= 15;
  }

  if (urgency.includes('90 días') && budget.includes('sí')) {
    // Tiene presupuesto pero no urgencia = research mode
    flags.push('has_budget_no_urgency');
    penalty -= 10;
  }

  // 5. Channel Maturity
  const matureChannels = ['linkedin', 'email', 'crm', 'web', 'ecommerce'];
  const socialChannels = ['instagram', 'tiktok', 'facebook', 'youtube'];

  let isMatureChannel = matureChannels.some(ch => channel.includes(ch));
  let isSocialChannel = socialChannels.some(ch => channel.includes(ch));

  if (isMatureChannel && (revenue.includes('10k') || revenue.includes('50k'))) {
    // Coherente: canal B2B + revenue alto
    consistencyScore += 15;
  }

  if (isSocialChannel && revenue.includes('50k')) {
    // Puede ser creator/influencer - validar con team
    if (team.includes('solo') || team.includes('1-3')) {
      consistencyScore += 10; // Coherente para creator
    }
  }

  // ============ SCORING FINAL DE COHERENCIA ============
  if (consistencyScore >= 90) flags.push('highly_consistent');
  else if (consistencyScore < 50) flags.push('highly_inconsistent');

  return { flags, penalty, consistencyScore };
}

// ========================================
// 3. DETECTOR DE PRESUPUESTO FALSO ULTRA
// ========================================
function detectFakeBudgetUltra(budget, revenue, urgency, painQuality, techInvestment) {
  const budgetLower = (budget || '').toLowerCase();
  const revenueLower = (revenue || '').toLowerCase();
  const urgencyLower = (urgency || '').toLowerCase();
  const techLower = (techInvestment || '').toLowerCase();

  let isFake = false;
  let confidence = 0;
  let reasons = [];

  // Solo analizar si dice "Sí"
  if (budgetLower.includes('sí')) {

    // Señal 1: Revenue muy bajo
    if (revenueLower.includes('0-2k')) {
      confidence += 35;
      reasons.push('revenue_too_low');
    }

    // Señal 2: Sin urgencia real
    if (urgencyLower.includes('90 días') || urgencyLower.includes('3 meses')) {
      confidence += 25;
      reasons.push('no_real_urgency');
    }

    // Señal 3: Dolor genérico (no sabe qué problema tiene pero tiene $5k?)
    if (painQuality === 'low' || painQuality === 'invalid') {
      confidence += 45; // SEÑAL FUERTE
      reasons.push('generic_pain');
    }

    // Señal 4: Nunca invirtió en tech (primer timer = riesgo)
    if (techLower.includes('no')) {
      confidence += 20;
      reasons.push('no_tech_history');
    }

    // Señal 5: Dice "posible" no "sí" (evasivo)
    if (budgetLower.includes('posible')) {
      confidence += 15;
      reasons.push('uncertain_budget');
    }

    if (confidence >= 60) isFake = true;

  } else if (budgetLower.includes('posible')) {
    // "Posible" = maybe, watch out
    if (painQuality === 'low') {
      confidence += 40;
      isFake = true;
      reasons.push('uncertain_with_low_pain');
    }
  }

  return { isFake, confidence, reasons };
}

// ========================================
// 4. ANÁLISIS DE MADUREZ DEL NEGOCIO
// ========================================
function analyzeBusinessMaturity(data) {
  let maturityScore = 0;
  let stage = 'early'; // early, growth, scale

  const revenue = (data.monthlyRevenue || '').toLowerCase();
  const team = (data.teamSize || '').toLowerCase();
  const channel = (data.mainChannel || '').toLowerCase();
  const tech = (data.techInvestment || '').toLowerCase();

  // Revenue stage
  if (revenue.includes('50k')) maturityScore += 40;
  else if (revenue.includes('10k')) maturityScore += 25;
  else if (revenue.includes('2k-10k')) maturityScore += 15;

  // Team stage
  if (team.includes('10+')) maturityScore += 30;
  else if (team.includes('4-10')) maturityScore += 20;
  else if (team.includes('1-3')) maturityScore += 10;

  // Tech adoption
  if (tech.includes('sí')) maturityScore += 15;

  // Channel sophistication
  if (channel.includes('crm') || channel.includes('email') || channel.includes('linkedin')) {
    maturityScore += 10;
  }

  if (maturityScore >= 70) stage = 'scale';
  else if (maturityScore >= 35) stage = 'growth';

  return { maturityScore, stage };
}

// ========================================
// 5. ANÁLISIS DE COMMITMENT
// ========================================
function analyzeCommitment(data, painAnalysis) {
  let commitmentScore = 0;

  // 1. Completó todo el protocolo
  const completion = parseInt(data.percentComplete) || 0;
  if (completion >= 95) commitmentScore += 30;
  else if (completion >= 80) commitmentScore += 20;
  else if (completion < 50) commitmentScore -= 20;

  // 2. Dio respuestas largas y detalladas
  if (painAnalysis.length >= 80) commitmentScore += 25;
  else if (painAnalysis.length < 20) commitmentScore -= 15;

  // 3. Info adicional (optional pero lo llenó)
  if (data.additionalInfo && data.additionalInfo.length > 20) {
    commitmentScore += 20;
  }

  // 4. Canal username (compartió su handle)
  if (data.channelUsername && data.channelUsername.length > 3) {
    commitmentScore += 10;
  }

  return { commitmentScore };
}

// ========================================
// EJECUCIÓN PRINCIPAL
// ========================================

// Scores base del sistema original
let completionScore = scoringInput.completionScore * CONFIG.weights.completion;
let budgetScore = scoringInput.budgetScore * CONFIG.weights.budget;
let revenueScore = scoringInput.revenueScore * CONFIG.weights.revenue;
let teamScore = scoringInput.teamScore * CONFIG.weights.team;
let urgencyScore = scoringInput.urgencyScore * CONFIG.weights.urgency;

// Engagement
let engagementScore = 0;
if (raw.channelUsername && raw.channelUsername.length > 3) {
  engagementScore = 10 * CONFIG.weights.engagement;
}

// ========================================
// ANÁLISIS ULTRA AVANZADOS
// ========================================

// 1. Dolor ultra profundo
const painAnalysis = analyzePainQualityUltra(raw.mainPain, raw.additionalInfo);
const painQualityScore = painAnalysis.score * CONFIG.weights.painQuality;

// 2. Coherencia ultra
const consistencyAnalysis = analyzeProfileConsistencyUltra(raw);
const consistencyScore = (consistencyAnalysis.consistencyScore / 100) * 50 * CONFIG.weights.consistency;

// 3. Presupuesto falso ultra
const budgetAnalysis = detectFakeBudgetUltra(
  raw.budget5k, 
  raw.monthlyRevenue, 
  raw.urgency, 
  painAnalysis.quality,
  raw.techInvestment
);

// 4. Madurez del negocio
const maturityAnalysis = analyzeBusinessMaturity(raw);
const maturityScore = (maturityAnalysis.maturityScore / 100) * 40 * CONFIG.weights.maturity;

// 5. Commitment
const commitmentAnalysis = analyzeCommitment(protocolData, painAnalysis);
const commitmentScore = (commitmentAnalysis.commitmentScore / 100) * 35 * CONFIG.weights.commitment;

// ========================================
// PENALIZACIONES Y BONUSES
// ========================================

let penalties = 0;
let bonuses = 0;
let redFlags = [];
let greenFlags = [];

// PENALIZACIONES

if (protocolData.percentComplete < 80) {
  penalties += CONFIG.penalties.incompleteProtocol;
  redFlags.push('incomplete_protocol');
}

if (painAnalysis.flags.includes('highly_generic') || painAnalysis.flags.includes('generic_response')) {
  penalties += CONFIG.penalties.genericPain;
  redFlags.push('generic_pain');
}

if (painAnalysis.flags.includes('extremely_short') || painAnalysis.flags.includes('too_short')) {
  penalties += CONFIG.penalties.tooShortPain;
  redFlags.push('short_pain');
}

if (painAnalysis.flags.includes('copy_paste_detected')) {
  penalties += CONFIG.penalties.copyPaste;
  redFlags.push('copy_paste');
}

if (painAnalysis.flags.includes('curiosity_seeker')) {
  penalties += CONFIG.penalties.curiositySeeker;
  redFlags.push('tourist');
}

if (consistencyAnalysis.penalty < 0) {
  penalties += consistencyAnalysis.penalty;
  redFlags = redFlags.concat(consistencyAnalysis.flags);
}

if (budgetAnalysis.isFake) {
  penalties += CONFIG.penalties.fakeBudget;
  redFlags.push('fake_budget');
}

if (maturityAnalysis.stage === 'early' && budgetAnalysis.confidence > 30) {
  penalties += CONFIG.penalties.immatureProfile;
  redFlags.push('immature_profile');
}

if (commitmentAnalysis.commitmentScore < 30) {
  penalties += CONFIG.penalties.lowCommitment;
  redFlags.push('low_commitment');
}

// BONUSES

if (painAnalysis.quality === 'ultra_high') {
  bonuses += CONFIG.bonuses.ultraSpecific;
  greenFlags.push('ultra_specific_pain');
}

if (painAnalysis.sentiment === 'urgent' && painAnalysis.quality === 'high') {
  bonuses += CONFIG.bonuses.urgentAndSerious;
  greenFlags.push('urgent_and_serious');
}

if (maturityAnalysis.stage === 'scale') {
  bonuses += CONFIG.bonuses.provenRevenue;
  greenFlags.push('proven_revenue');
}

if (raw.teamSize && (raw.teamSize.includes('4') || raw.teamSize.includes('10'))) {
  bonuses += CONFIG.bonuses.teamReady;
  greenFlags.push('team_ready');
}

if (painAnalysis.categoryScores && painAnalysis.categoryScores.técnico > 0) {
  bonuses += CONFIG.bonuses.techSavvy;
  greenFlags.push('tech_savvy');
}

// ========================================
// CÁLCULO FINAL ULTRA
// ========================================

const rawScore = 
  completionScore + 
  budgetScore + 
  revenueScore + 
  teamScore + 
  urgencyScore + 
  engagementScore + 
  painQualityScore +
  consistencyScore +
  maturityScore +
  commitmentScore +
  bonuses +
  penalties;

// Normalizar a 0-100
const normalizedScore = Math.max(0, Math.min(100, Math.round((rawScore + 50) / 250 * 100)));

// Categorización
let category, label, recommendation;

if (normalizedScore >= CONFIG.thresholds.HIGH_VALUE) {
  category = 'HIGH_VALUE'; 
  label = 'HIGH VALUE';
  recommendation = 'Llamar inmediatamente. Enviar regalo premium.';
} else if (normalizedScore >= CONFIG.thresholds.READY) {
  category = 'READY'; 
  label = 'READY';
  recommendation = 'Confirmar llamada. Enviar recurso educativo.';
} else if (normalizedScore >= CONFIG.thresholds.WARM) {
  category = 'WARM'; 
  label = 'WARM';
  recommendation = 'Revisar respuestas antes de llamar. Nurture sequence.';
} else {
  category = 'COLD'; 
  label = 'COLD';
  recommendation = 'No califica. Email de reprogramación o descarte.';
}

// ========================================
// OUTPUT ULTRA ENRIQUECIDO
// ========================================

const output = {
  leadId: protocolData.leadId,
  email: protocolData.email,
  fullName: protocolData.fullName,

  scoring: { 
    normalizedScore, 
    category, 
    label,
    recommendation,

    // Breakdown ultra detallado
    breakdown: {
      completion: Math.round(completionScore),
      budget: Math.round(budgetScore),
      revenue: Math.round(revenueScore),
      team: Math.round(teamScore),
      urgency: Math.round(urgencyScore),
      engagement: Math.round(engagementScore),
      painQuality: Math.round(painQualityScore),
      consistency: Math.round(consistencyScore),
      maturity: Math.round(maturityScore),
      commitment: Math.round(commitmentScore),
      bonuses: Math.round(bonuses),
      penalties: Math.round(penalties),
      rawTotal: Math.round(rawScore)
    },

    // Análisis de calidad ultra
    intelligence: {
      painAnalysis: {
        quality: painAnalysis.quality,
        sentiment: painAnalysis.sentiment,
        specificity: painAnalysis.specificity,
        length: painAnalysis.length,
        wordCount: painAnalysis.wordCount,
        specificWords: painAnalysis.specificWords,
        genericWords: painAnalysis.genericWords,
        numberCount: painAnalysis.numberCount,
        categoryScores: painAnalysis.categoryScores,
        flags: painAnalysis.flags
      },

      consistencyAnalysis: {
        score: consistencyAnalysis.consistencyScore,
        isConsistent: consistencyAnalysis.consistencyScore >= 70,
        flags: consistencyAnalysis.flags
      },

      budgetAnalysis: {
        isLikelyFake: budgetAnalysis.isFake,
        confidence: budgetAnalysis.confidence,
        reasons: budgetAnalysis.reasons
      },

      maturityAnalysis: {
        score: maturityAnalysis.maturityScore,
        stage: maturityAnalysis.stage
      },

      commitmentAnalysis: {
        score: commitmentAnalysis.commitmentScore,
        isCommitted: commitmentAnalysis.commitmentScore >= 50
      }
    },

    // Flags consolidadas
    redFlags: redFlags,
    greenFlags: greenFlags,

    // Indicadores finales
    isSuspicious: redFlags.length >= 3,
    isHighQuality: greenFlags.length >= 2 && redFlags.length === 0,
    closeability: normalizedScore >= 75 ? 'high' : normalizedScore >= 60 ? 'medium' : 'low'
  },

  protocol: protocolData,

  sheetUpdate: {
    Score: normalizedScore,
    Categoria: category,
    Estado: 'Scoring Completado'
  }
};

return [{ json: output }];

