// ═══════════════════════════════════════════════════════════════════════════
// PROTOCOL DEADLINE ENGINE v6.0 - ULTRA INTELLIGENCE
// AI-Powered Lead Management System
// ═══════════════════════════════════════════════════════════════════════════

const protocolsRaw = $('Fetch All Protocols').all();
const onboardingRaw = $('Fetch Onboarding Data').all();

// ═══════════════════════════════════════════════════════════════════════════
// ULTRA CONFIGURATION
// ═══════════════════════════════════════════════════════════════════════════

const CONFIG = {
  reminders: {
    REMINDER_1: 48,
    REMINDER_2: 24,
    FINAL_WARNING: 6,
  },

  // Multi-level terminal state detection
  terminalPatterns: {
    estados: ['completed', 'expired', 'scoring completado', 'completado', 'expirado', 'reprogramado', 'protocol timeout'],
    categorias: ['cold', 'disqualified', 'no show', 'spam', 'invalid'],
    keywords: ['cancelado', 'rechazado', 'no interesado', 'no responde']
  },

  reminderLevels: {
    'reminder 1 sent': 1,
    'reminder 2 sent': 2,
    'final warning sent': 3,
    'reminder sent': 1
  },

  // Intelligent timing
  timezone: 'America/Bogota',
  businessHours: { start: 8, end: 21 },

  // Quality thresholds
  qualityThresholds: {
    minScore: 30,
    minFacturacion: 5000,
    optimalResponseTime: 24 // horas
  },

  // Smart throttling (evitar spam)
  throttling: {
    maxEmailsPerHour: 10,
    minIntervalBetweenEmails: 5 // minutos
  },

  // Predictive weights
  weights: {
    score: 0.3,
    facturacion: 0.25,
    urgencia: 0.2,
    tiempoRespuesta: 0.15,
    categoria: 0.1
  }
};

// ═══════════════════════════════════════════════════════════════════════════
// ADVANCED UTILITIES
// ═══════════════════════════════════════════════════════════════════════════

class DateUtils {
  static parse(dateStr) {
    if (!dateStr) return null;
    const d = new Date(dateStr);
    return isNaN(d.getTime()) ? null : d;
  }

  static hoursBetween(date1, date2) {
    return (date2 - date1) / (1000 * 60 * 60);
  }

  static isBusinessHours(timezone = CONFIG.timezone) {
    const now = new Date();
    const local = new Date(now.toLocaleString('en-US', { timeZone: timezone }));
    const hour = local.getHours();
    const day = local.getDay();

    // Weekend check
    if (day === 0 || day === 6) return false;

    return hour >= CONFIG.businessHours.start && hour <= CONFIG.businessHours.end;
  }

  static formatBogota(date) {
    if (!date) return 'Fecha no disponible';
    return new Date(date).toLocaleString('es-CO', { 
      timeZone: CONFIG.timezone,
      weekday: 'long',
      year: 'numeric',
      month: 'long',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  }

  static getOptimalSendTime() {
    const now = new Date();
    const bogota = new Date(now.toLocaleString('en-US', { timeZone: CONFIG.timezone }));
    const hour = bogota.getHours();

    // Si es muy temprano, esperar a las 9 AM
    if (hour < 9) return 9;
    // Si es hora de almuerzo (12-2 PM), esperar a las 2 PM
    if (hour >= 12 && hour < 14) return 14;
    // Si es muy tarde, programar para mañana 9 AM
    if (hour >= 19) return 9;

    return hour;
  }
}

class EmailValidator {
  static isValid(email) {
    if (!email) return false;
    const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return regex.test(email.toLowerCase().trim());
  }

  static normalize(email) {
    return email.toLowerCase().trim();
  }

  static getDomain(email) {
    if (!email) return null;
    return email.split('@')[1];
  }

  static isDisposable(email) {
    const disposableDomains = ['tempmail.com', 'guerrillamail.com', '10minutemail.com'];
    const domain = this.getDomain(email);
    return domain ? disposableDomains.includes(domain) : false;
  }

  static fuzzyMatch(email1, email2) {
    const e1 = this.normalize(email1);
    const e2 = this.normalize(email2);

    // Exact match
    if (e1 === e2) return 1.0;

    // Levenshtein distance (simple implementation)
    const len1 = e1.length;
    const len2 = e2.length;
    const maxLen = Math.max(len1, len2);

    let matches = 0;
    for (let i = 0; i < Math.min(len1, len2); i++) {
      if (e1[i] === e2[i]) matches++;
    }

    return matches / maxLen;
  }
}

class LeadScorer {
  static calculateEngagementScore(lead) {
    let score = 0;

    // Score base (si existe)
    if (lead.score && lead.score > 0) {
      score += (lead.score / 100) * CONFIG.weights.score;
    }

    // Facturación
    if (lead.facturacion) {
      const factNum = this.parseNumber(lead.facturacion);
      if (factNum >= 10000) score += CONFIG.weights.facturacion;
      else if (factNum >= 5000) score += CONFIG.weights.facturacion * 0.7;
      else if (factNum >= 3000) score += CONFIG.weights.facturacion * 0.4;
    }

    // Urgencia
    if (lead.urgencia) {
      const urg = lead.urgencia.toLowerCase();
      if (urg.includes('alta') || urg.includes('urgente')) {
        score += CONFIG.weights.urgencia;
      } else if (urg.includes('media')) {
        score += CONFIG.weights.urgencia * 0.6;
      }
    }

    // Tiempo de respuesta
    if (lead.hoursSinceSent <= CONFIG.qualityThresholds.optimalResponseTime) {
      score += CONFIG.weights.tiempoRespuesta;
    }

    // Categoría
    if (lead.categoria && !lead.categoria.toLowerCase().includes('cold')) {
      score += CONFIG.weights.categoria;
    }

    return Math.min(1.0, score);
  }

  static predictChurnProbability(lead) {
    let churnScore = 0;

    // Tiempo sin responder
    if (lead.hoursSinceSent > 48) churnScore += 0.3;
    else if (lead.hoursSinceSent > 24) churnScore += 0.2;

    // Recordatorios enviados
    if (lead.reminderLevel >= 2) churnScore += 0.25;
    else if (lead.reminderLevel >= 1) churnScore += 0.15;

    // Hora de la cita muy lejana (no urgente)
    if (lead.hoursUntilEvent > 72) churnScore += 0.15;

    // Score bajo
    if (lead.score < CONFIG.qualityThresholds.minScore) churnScore += 0.2;

    // Sin datos de facturación
    if (!lead.facturacion || this.parseNumber(lead.facturacion) === 0) {
      churnScore += 0.15;
    }

    return Math.min(1.0, churnScore);
  }

  static calculateLeadQuality(lead) {
    const engagement = this.calculateEngagementScore(lead);
    const churn = this.predictChurnProbability(lead);

    // Quality = engagement - churn risk
    const quality = Math.max(0, engagement - (churn * 0.5));

    if (quality >= 0.7) return 'HOT';
    if (quality >= 0.5) return 'WARM';
    if (quality >= 0.3) return 'COOL';
    return 'COLD';
  }

  static parseNumber(str) {
    if (!str) return 0;
    if (typeof str === 'number') return str;

    // Remove currency symbols and commas
    const cleaned = str.toString().replace(/[$,k]/gi, '');
    const num = parseFloat(cleaned);

    // Handle 'k' notation (5k = 5000)
    if (str.toLowerCase().includes('k')) {
      return num * 1000;
    }

    return isNaN(num) ? 0 : num;
  }
}

class TerminalStateDetector {
  static isTerminal(estado, categoria, notas = '') {
    if (!estado && !categoria) return false;

    const combined = `${estado || ''} ${categoria || ''} ${notas}`.toLowerCase();

    // Check estados
    for (const pattern of CONFIG.terminalPatterns.estados) {
      if (combined.includes(pattern.toLowerCase())) return true;
    }

    // Check categorias
    for (const pattern of CONFIG.terminalPatterns.categorias) {
      if (combined.includes(pattern.toLowerCase())) return true;
    }

    // Check keywords
    for (const keyword of CONFIG.terminalPatterns.keywords) {
      if (combined.includes(keyword)) return true;
    }

    return false;
  }

  static getReason(estado, categoria, notas = '') {
    const combined = `${estado || ''} ${categoria || ''} ${notas}`.toLowerCase();

    if (combined.includes('cold')) return 'Categoria COLD';
    if (combined.includes('completed') || combined.includes('completado')) return 'Completado';
    if (combined.includes('expired') || combined.includes('expirado')) return 'Expirado';
    if (combined.includes('cancel') || combined.includes('reprogramado')) return 'Cancelado/Reprogramado';
    if (combined.includes('no interesado')) return 'No interesado';

    return 'Estado terminal';
  }
}

class OnboardingMatcher {
  static findBestMatch(email, onboardingData) {
    if (!email) return null;
    const emailNorm = EmailValidator.normalize(email);

    let bestMatch = null;
    let bestScore = 0;

    for (const item of onboardingData) {
      const onbEmail = item.json.Email;
      if (!onbEmail) continue;

      const similarity = EmailValidator.fuzzyMatch(emailNorm, onbEmail);

      if (similarity > bestScore) {
        bestScore = similarity;
        bestMatch = item;
      }

      // Exact match, stop searching
      if (similarity === 1.0) break;
    }

    // Only return if similarity is high enough (>= 80%)
    if (bestScore >= 0.8) {
      return {
        eventDateUTC: bestMatch.json['Fecha Evento (UTC)'],
        eventDateBogota: bestMatch.json['Fecha Evento (America/Bogota)'],
        eventType: bestMatch.json['Tipo de Evento'],
        nombre: bestMatch.json['Nombre'],
        telefono: bestMatch.json['Teléfono'],
        matchScore: bestScore
      };
    }

    return null;
  }
}

class ReminderLevelDetector {
  static getLevel(estado, notas = '') {
    if (!estado && !notas) return 0;

    const combined = `${estado || ''} ${notas}`.toLowerCase();

    // Check exact patterns first
    for (const [pattern, level] of Object.entries(CONFIG.reminderLevels)) {
      if (combined.includes(pattern)) return level;
    }

    // Fallback to numeric detection
    if (combined.includes('reminder 3') || combined.includes('3')) return 3;
    if (combined.includes('reminder 2') || combined.includes('2')) return 2;
    if (combined.includes('reminder 1') || combined.includes('1')) return 1;

    return 0;
  }
}

class AnomalyDetector {
  static detectAnomalies(lead) {
    const anomalies = [];

    // Email sin nombre
    if (!lead.nombre || lead.nombre === 'Lead') {
      anomalies.push({ type: 'missing_name', severity: 'low' });
    }

    // Score muy bajo
    if (lead.score < 20) {
      anomalies.push({ type: 'very_low_score', severity: 'medium', value: lead.score });
    }

    // Cita en menos de 1 hora pero protocolo no completado
    if (lead.hoursUntilEvent < 1 && lead.hoursUntilEvent > 0) {
      anomalies.push({ type: 'imminent_call_no_protocol', severity: 'critical' });
    }

    // Cita ya pasó (negativo)
    if (lead.hoursUntilEvent < 0) {
      anomalies.push({ type: 'event_in_past', severity: 'critical', value: lead.hoursUntilEvent });
    }

    // Timestamp del protocolo en el futuro (imposible)
    if (lead.hoursSinceSent < 0) {
      anomalies.push({ type: 'future_timestamp', severity: 'critical' });
    }

    // Email desechable
    if (EmailValidator.isDisposable(lead.email)) {
      anomalies.push({ type: 'disposable_email', severity: 'high' });
    }

    // Sin datos de facturación en lead HOT
    if (lead.leadQuality === 'HOT' && !lead.facturacion) {
      anomalies.push({ type: 'hot_lead_missing_revenue', severity: 'medium' });
    }

    return anomalies;
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// MAIN PROCESSING ENGINE
// ═══════════════════════════════════════════════════════════════════════════

const now = new Date();
const processedEmails = new Set();
const emailSendLog = []; // For throttling

const results = {
  reminder1: [],
  reminder2: [],
  finalWarning: [],
  expired: []
};

const stats = {
  total: protocolsRaw.length,
  processed: 0,
  duplicates: 0,
  terminal: 0,
  cold: 0,
  invalidEmails: 0,
  disposableEmails: 0,
  noEventDate: 0,
  notDueYet: 0,
  alreadySent: 0,
  outsideHours: 0,
  lowQuality: 0,
  anomaliesDetected: 0,
  fuzzyMatches: 0
};

const skipped = [];
const anomalyLog = [];

console.log(`🚀 Processing ${protocolsRaw.length} protocols...`);

for (const item of protocolsRaw) {
  const data = item.json;
  const rawEmail = data.Email || '';
  const estado = data.Estado || '';
  const categoria = data.Categoria || '';
  const notas = data.Notas || '';
  const timestamp = data.Timestamp;

  // ─── VALIDATION LAYER 1: Email ───
  if (!EmailValidator.isValid(rawEmail)) {
    stats.invalidEmails++;
    skipped.push({ email: rawEmail || 'vacío', reason: 'email_invalido' });
    continue;
  }

  const email = EmailValidator.normalize(rawEmail);

  // Check disposable
  if (EmailValidator.isDisposable(email)) {
    stats.disposableEmails++;
    skipped.push({ email, reason: 'disposable_email' });
    continue;
  }

  // ─── VALIDATION LAYER 2: Deduplication ───
  if (processedEmails.has(email)) {
    stats.duplicates++;
    continue;
  }
  processedEmails.add(email);

  // ─── VALIDATION LAYER 3: Terminal State Detection ───
  if (TerminalStateDetector.isTerminal(estado, categoria, notas)) {
    const reason = TerminalStateDetector.getReason(estado, categoria, notas);

    if (categoria.toLowerCase().includes('cold')) {
      stats.cold++;
    } else {
      stats.terminal++;
    }

    skipped.push({ email, reason: 'terminal_state', detail: reason, estado, categoria });
    continue;
  }

  // ─── DATA ENRICHMENT: Find Event Data ───
  const eventData = OnboardingMatcher.findBestMatch(email, onboardingRaw);

  if (!eventData) {
    stats.noEventDate++;
    skipped.push({ email, reason: 'sin_fecha_cita' });
    continue;
  }

  // Track fuzzy matches
  if (eventData.matchScore < 1.0) {
    stats.fuzzyMatches++;
  }

  const eventDate = DateUtils.parse(eventData.eventDateUTC);
  if (!eventDate) {
    skipped.push({ email, reason: 'fecha_invalida', raw: eventData.eventDateUTC });
    continue;
  }

  // ─── TIME CALCULATIONS ───
  const hoursUntilEvent = DateUtils.hoursBetween(now, eventDate);
  const hoursSinceSent = timestamp ? DateUtils.hoursBetween(DateUtils.parse(timestamp), now) : 0;

  // Build enriched lead object
  const lead = {
    email: email,
    nombre: eventData.nombre || data.Nombre || 'Lead',
    firstName: (eventData.nombre || data.Nombre || 'Lead').split(' ')[0],
    telefono: eventData.telefono || '',

    eventDateBogota: eventData.eventDateBogota || DateUtils.formatBogota(eventDate),
    eventDateUTC: eventData.eventDateUTC,
    eventType: eventData.eventType || 'Sales Call',

    hoursUntilEvent: Math.round(hoursUntilEvent * 10) / 10,
    hoursSinceSent: Math.round(hoursSinceSent * 10) / 10,

    score: parseInt(data.Score) || 0,
    categoria: categoria,
    estadoActual: estado,

    dolorPrincipal: data.DolorPrincipal || '',
    facturacion: data.Facturacion || '',
    presupuesto: data.Presupuesto5k || '',
    urgencia: data.Urgencia || '',

    reminderLevel: ReminderLevelDetector.getLevel(estado, notas),
    matchScore: eventData.matchScore
  };

  // ─── INTELLIGENT SCORING ───
  lead.engagementScore = LeadScorer.calculateEngagementScore(lead);
  lead.churnProbability = LeadScorer.predictChurnProbability(lead);
  lead.leadQuality = LeadScorer.calculateLeadQuality(lead);

  // ─── ANOMALY DETECTION ───
  lead.anomalies = AnomalyDetector.detectAnomalies(lead);
  if (lead.anomalies.length > 0) {
    stats.anomaliesDetected++;
    anomalyLog.push({ email, anomalies: lead.anomalies });
  }

  // ─── QUALITY FILTER ───
  if (lead.leadQuality === 'COLD' && lead.score < CONFIG.qualityThresholds.minScore) {
    stats.lowQuality++;
    skipped.push({ 
      email, 
      reason: 'baja_calidad', 
      quality: lead.leadQuality,
      score: lead.score,
      churnProb: Math.round(lead.churnProbability * 100) + '%'
    });
    continue;
  }

  // ─── ACTION DETERMINATION ───
  let action = null;

  if (hoursUntilEvent < 0) {
    if (lead.reminderLevel < 4) {
      action = 'EXPIRED';
    }
  }
  else if (hoursUntilEvent <= CONFIG.reminders.FINAL_WARNING) {
    if (lead.reminderLevel < 3) {
      action = 'FINAL_WARNING';
    } else {
      stats.alreadySent++;
      skipped.push({ email, reason: 'final_warning_ya_enviado' });
      continue;
    }
  }
  else if (hoursUntilEvent <= CONFIG.reminders.REMINDER_2) {
    if (lead.reminderLevel < 2) {
      action = 'REMINDER_2';
    } else {
      stats.alreadySent++;
      skipped.push({ email, reason: 'reminder2_ya_enviado' });
      continue;
    }
  }
  else if (hoursUntilEvent <= CONFIG.reminders.REMINDER_1) {
    if (lead.reminderLevel < 1) {
      action = 'REMINDER_1';
    } else {
      stats.alreadySent++;
      skipped.push({ email, reason: 'reminder1_ya_enviado' });
      continue;
    }
  }
  else {
    stats.notDueYet++;
    skipped.push({ 
      email, 
      reason: 'cita_lejana', 
      horasHastaCita: Math.round(hoursUntilEvent),
      quality: lead.leadQuality
    });
    continue;
  }

  if (!action) {
    skipped.push({ email, reason: 'sin_accion_definida' });
    continue;
  }

  // ─── BUSINESS HOURS CHECK (except EXPIRED) ───
  if (!DateUtils.isBusinessHours() && action !== 'EXPIRED') {
    stats.outsideHours++;
    skipped.push({ 
      email, 
      reason: 'fuera_horario', 
      action,
      nextOptimalHour: DateUtils.getOptimalSendTime()
    });
    continue;
  }

  // ─── FINAL ENRICHMENT ───
  stats.processed++;
  lead.actionType = action;
  lead.processedAt = now.toISOString();
  lead.optimalSendTime = DateUtils.getOptimalSendTime();

  // Route to appropriate array
  switch (action) {
    case 'REMINDER_1': results.reminder1.push(lead); break;
    case 'REMINDER_2': results.reminder2.push(lead); break;
    case 'FINAL_WARNING': results.finalWarning.push(lead); break;
    case 'EXPIRED': results.expired.push(lead); break;
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// INTELLIGENT OUTPUT GENERATION
// ═══════════════════════════════════════════════════════════════════════════

const totalActions = results.reminder1.length + results.reminder2.length + 
                     results.finalWarning.length + results.expired.length;

// Calculate quality distribution
const qualityDistribution = {
  hot: 0,
  warm: 0,
  cool: 0,
  cold: 0
};

const allProcessedLeads = [
  ...results.reminder1,
  ...results.reminder2,
  ...results.finalWarning,
  ...results.expired
];

for (const lead of allProcessedLeads) {
  qualityDistribution[lead.leadQuality.toLowerCase()]++;
}

const summary = {
  // Basic stats
  ...stats,

  // Action counts
  reminder1Count: results.reminder1.length,
  reminder2Count: results.reminder2.length,
  finalWarningCount: results.finalWarning.length,
  expiredCount: results.expired.length,
  totalActions,

  // Quality metrics
  qualityDistribution,
  avgEngagementScore: allProcessedLeads.length > 0 
    ? (allProcessedLeads.reduce((sum, l) => sum + l.engagementScore, 0) / allProcessedLeads.length).toFixed(2)
    : 0,
  avgChurnProbability: allProcessedLeads.length > 0
    ? (allProcessedLeads.reduce((sum, l) => sum + l.churnProbability, 0) / allProcessedLeads.length).toFixed(2)
    : 0,

  // System status
  isBusinessHours: DateUtils.isBusinessHours(),
  optimalSendTime: DateUtils.getOptimalSendTime(),
  processedAt: now.toISOString(),

  // Advanced metrics
  conversionReadiness: allProcessedLeads.filter(l => l.leadQuality === 'HOT').length,
  atRiskLeads: allProcessedLeads.filter(l => l.churnProbability > 0.7).length,
  criticalAnomalies: anomalyLog.filter(a => 
    a.anomalies.some(an => an.severity === 'critical')
  ).length
};

console.log(`✅ Processed: ${stats.processed} | Actions: ${totalActions}`);
console.log(`📊 Quality: HOT=${qualityDistribution.hot} WARM=${qualityDistribution.warm} COOL=${qualityDistribution.cool} COLD=${qualityDistribution.cold}`);
console.log(`⚠️ Anomalies: ${stats.anomaliesDetected} (${summary.criticalAnomalies} critical)`);

// ═══════════════════════════════════════════════════════════════════════════
// OUTPUT
// ═══════════════════════════════════════════════════════════════════════════

if (totalActions === 0) {
  return [{ 
    json: { 
      noAction: true, 
      summary,
      topSkipReasons: skipped.slice(0, 10),
      anomalies: anomalyLog.slice(0, 5)
    } 
  }];
}

// Sort by priority (HOT first, then by hours until event)
const sortedLeads = allProcessedLeads.sort((a, b) => {
  // Priority 1: Quality
  const qualityOrder = { 'HOT': 4, 'WARM': 3, 'COOL': 2, 'COLD': 1 };
  const qualityDiff = qualityOrder[b.leadQuality] - qualityOrder[a.leadQuality];
  if (qualityDiff !== 0) return qualityDiff;

  // Priority 2: Hours until event (sooner first)
  return a.hoursUntilEvent - b.hoursUntilEvent;
});

return [
  { 
    json: { 
      isSummary: true, 
      summary,
      topSkipReasons: skipped.slice(0, 5),
      criticalAnomalies: anomalyLog.filter(a => 
        a.anomalies.some(an => an.severity === 'critical')
      ),
      recommendations: {
        hotLeads: sortedLeads.filter(l => l.leadQuality === 'HOT').length,
        needsUrgentAttention: sortedLeads.filter(l => 
          l.hoursUntilEvent < 12 && l.reminderLevel < 2
        ).length,
        likelyToChurn: sortedLeads.filter(l => l.churnProbability > 0.7).length
      }
    } 
  },
  ...sortedLeads.map(lead => ({ json: lead }))
];

