// SECTION 3: UTILITY FUNCTIONS
// ═══════════════════════════════════════════════════════════════════════════

const Utils = {

  // ─────────────────────────────────────────────────────────────────────────
  // 3.1 TEXT NORMALIZATION
  // ─────────────────────────────────────────────────────────────────────────
  normalizar(texto) {
    if (!texto) return '';
    return texto.toString().toLowerCase()
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .replace(/[^\w\s]/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
  },

  // ─────────────────────────────────────────────────────────────────────────
  // 3.2 CAPITALIZE
  // ─────────────────────────────────────────────────────────────────────────
  capitalizar(texto) {
    if (!texto || texto.length === 0) return '';
    return texto.charAt(0).toUpperCase() + texto.slice(1).toLowerCase();
  },

  // ─────────────────────────────────────────────────────────────────────────
  // 3.3 RANDOM SELECTION
  // ─────────────────────────────────────────────────────────────────────────
  random(arr) {
    if (!arr || arr.length === 0) return '';
    return arr[Math.floor(Math.random() * arr.length)];
  },

  // ─────────────────────────────────────────────────────────────────────────
  // 3.4 TIME OF DAY
  // ─────────────────────────────────────────────────────────────────────────
  getTimeOfDay() {
    const hour = new Date().getHours();
    if (hour >= 5 && hour < 12) return 'morning';
    if (hour >= 12 && hour < 18) return 'afternoon';
    if (hour >= 18 && hour < 22) return 'evening';
    return 'night';
  },

  // ─────────────────────────────────────────────────────────────────────────
  // 3.5 DAY OF WEEK
  // ─────────────────────────────────────────────────────────────────────────
  getDayContext() {
    const day = new Date().getDay();
    if (day === 0 || day === 6) return 'weekend';
    if (day === 1) return 'monday';
    if (day === 5) return 'friday';
    return 'weekday';
  },

  // ─────────────────────────────────────────────────────────────────────────
  // 3.6 FORMAT DATE
  // ─────────────────────────────────────────────────────────────────────────
  formatDate(date) {
    return new Date(date || Date.now()).toLocaleDateString('es-ES', { 
      weekday: 'long', 
      year: 'numeric', 
      month: 'long', 
      day: 'numeric' 
    });
  }
};


// ═══════════════════════════════════════════════════════════════════════════
// SECTION 4: NAME PROCESSOR
// ═══════════════════════════════════════════════════════════════════════════

const NameProcessor = {

  extract(nombreCompleto) {
    if (!nombreCompleto || typeof nombreCompleto !== 'string') return null;

    let nombre = nombreCompleto.trim().replace(/\s+/g, ' ');
    if (!nombre || nombre.length < 2) return null;

    // Check generic names
    const nombreNorm = Utils.normalizar(nombre);
    const isGeneric = CONFIG.nombresGenericos.some(gen => {
      const genNorm = Utils.normalizar(gen);
      return nombreNorm === genNorm || 
             (nombreNorm.length < 20 && nombreNorm.includes(genNorm));
    });

    if (isGeneric) return null;

    // Split and filter parts
    const partes = nombre.split(' ')
      .filter(p => p.length > 1)
      .filter(p => !CONFIG.palabrasProhibidas.some(
        bad => Utils.normalizar(p).includes(Utils.normalizar(bad))
      ));

    if (partes.length === 0) return null;

    // Skip titles
    let idx = 0;
    const firstNorm = Utils.normalizar(partes[0]).replace(/\./g, '');
    if (CONFIG.titulos.includes(firstNorm) && partes.length > 1) {
      idx = 1;
    }

    // Get first valid name
    let firstName = partes[idx];

    // Validate it's a real name (has vowels, etc.)
    if (!firstName || firstName.length < 2 || /^[^a-záéíóúñ]+$/i.test(firstName)) {
      for (let i = idx + 1; i < partes.length; i++) {
        if (partes[i].length >= 2 && /[aeiouáéíóú]/i.test(partes[i])) {
          firstName = partes[i];
          break;
        }
      }
    }

    if (!firstName || firstName.length < 2) return null;

    return Utils.capitalizar(firstName);
  }
};


// ═══════════════════════════════════════════════════════════════════════════
// SECTION 5: PAIN POINT ANALYZER
// ═══════════════════════════════════════════════════════════════════════════

const PainAnalyzer = {

  process(painPoint) {
    const result = { 
      texto: null, 
      hasValid: false, 
      categoria: 'general',
      subcategoria: null,
      intensidad: 'medium',  // low, medium, high, critical
      keywords: [],
      sentiment: 'neutral'   // negative, neutral, positive
    };

    if (!painPoint || typeof painPoint !== 'string') return result;

    let texto = painPoint.trim().replace(/\s+/g, ' ');
    if (!texto || texto.length < 8) return result;

    const textoNorm = Utils.normalizar(texto);

    // Check empty responses
    const isEmpty = CONFIG.painPointsVacios.some(empty => {
      const emptyNorm = Utils.normalizar(empty);
      return textoNorm === emptyNorm || 
             textoNorm.startsWith(emptyNorm + ' ') ||
             (textoNorm.length < 25 && textoNorm.includes(emptyNorm));
    });

    if (isEmpty) return result;

    // Check profanity
    const hasProfanity = CONFIG.palabrasProhibidas.some(p => 
      textoNorm.includes(Utils.normalizar(p))
    );

    if (hasProfanity) return result;

    // Clean text
    texto = texto.charAt(0).toUpperCase() + texto.slice(1);
    if (texto.endsWith('.')) texto = texto.slice(0, -1);
    texto = texto.replace(/^["'""]/, '').replace(/["'""]$/, '');

    // Categorize
    for (const [cat, keywords] of Object.entries(CONFIG.painCategories)) {
      const matches = keywords.filter(kw => textoNorm.includes(kw));
      if (matches.length > 0) {
        result.categoria = cat;
        result.keywords = matches;
        break;
      }
    }

    // Detect intensity
    const urgentWords = ['urgente', 'inmediato', 'ya', 'ahora', 'crisis', 'desesperado', 
                         'muy', 'mucho', 'demasiado', 'imposible', 'no aguanto', 'hartx'];
    const criticalWords = ['quiebre', 'cerrar', 'bancarrota', 'perder todo', 'último recurso'];

    if (criticalWords.some(w => textoNorm.includes(w))) {
      result.intensidad = 'critical';
    } else if (urgentWords.filter(w => textoNorm.includes(w)).length >= 2) {
      result.intensidad = 'high';
    } else if (urgentWords.some(w => textoNorm.includes(w))) {
      result.intensidad = 'medium';
    } else {
      result.intensidad = 'low';
    }

    // Detect sentiment
    const negativeWords = ['problema', 'dolor', 'frustración', 'difícil', 'complicado', 
                           'no puedo', 'estresado', 'agotado', 'cansado', 'peor'];
    const positiveWords = ['quiero', 'busco', 'necesito', 'objetivo', 'meta', 'mejorar',
                           'crecer', 'escalar', 'optimizar', 'lograr'];

    const negCount = negativeWords.filter(w => textoNorm.includes(w)).length;
    const posCount = positiveWords.filter(w => textoNorm.includes(w)).length;

    if (negCount > posCount + 1) result.sentiment = 'negative';
    else if (posCount > negCount + 1) result.sentiment = 'positive';

    result.texto = texto;
    result.hasValid = true;

    return result;
  }
};


