// SECTION 6: DATA MERGER
// ═══════════════════════════════════════════════════════════════════════════

const DataMerger = {

  merge(protocolos, onboarding, scoring) {
    const merged = {
      // Sources
      sources: {
        hasProtocolos: !!protocolos,
        hasOnboarding: !!onboarding,
        hasScoring: !!scoring
      },

      // Basic Info
      nombre: protocolos?.Nombre || onboarding?.Nombre || scoring?.fullName || '',
      email: protocolos?.Email || onboarding?.Email || scoring?.email || '',
      telefono: onboarding?.['Teléfono'] || protocolos?.Telefono || '',

      // Protocol Data
      canal: protocolos?.Canal || '',
      usuario: protocolos?.Usuario || '',
      facturacion: protocolos?.Facturacion || '',
      equipo: protocolos?.Equipo || '',
      inversionTech: protocolos?.InversionTech || '',
      dolorPrincipal: protocolos?.DolorPrincipal || '',
      presupuesto5k: protocolos?.Presupuesto5k || '',
      urgencia: protocolos?.Urgencia || '',
      infoAdicional: protocolos?.InfoAdicional || '',
      industria: protocolos?.Industria || '',

      // Onboarding Data
      tipoEvento: onboarding?.['Tipo de Evento'] || 'Sales Call',
      fechaEventoUTC: onboarding?.['Fecha Evento (UTC)'] || '',
      fechaEvento: onboarding?.['Fecha Evento (America/Bogota)'] || '',
      calendlyLink: onboarding?.['Calendly Link'] || '',
      estado: onboarding?.Estado || protocolos?.Estado || '',
      notas: onboarding?.Notas || '',

      // Scoring
      score: scoring?.scoring?.normalizedScore || parseInt(protocolos?.Score) || 0,
      category: scoring?.scoring?.category || protocolos?.Categoria || 'UNKNOWN',

      // Inconsistencies
      inconsistencias: []
    };

    // Detect inconsistencies
    if (protocolos?.Nombre && onboarding?.Nombre) {
      const np = Utils.normalizar(protocolos.Nombre);
      const no = Utils.normalizar(onboarding.Nombre);
      if (np !== no && !np.includes(no) && !no.includes(np)) {
        merged.inconsistencias.push({
          tipo: 'nombre_diferente',
          protocolo: protocolos.Nombre,
          onboarding: onboarding.Nombre
        });
      }
    }

    if (!protocolos && onboarding) {
      merged.inconsistencias.push({ tipo: 'sin_protocolo' });
    }

    if (protocolos && !onboarding) {
      merged.inconsistencias.push({ tipo: 'sin_cita' });
    }

    return merged;
  }
};


