// SECTION 7: PROFILE ANALYZER
// ═══════════════════════════════════════════════════════════════════════════

const ProfileAnalyzer = {

  analyze(data) {
    const { facturacion, equipo, urgencia, presupuesto5k, inversionTech, 
            dolorPrincipal, canal, infoAdicional, industria } = data;

    let score = 0;
    let flags = [];
    let signals = { buy: 0, risk: 0, opportunity: 0 };

    // ───────────────────────────────────────────────────────────────────────
    // FACTURACIÓN (40 pts max)
    // ───────────────────────────────────────────────────────────────────────
    const factNorm = Utils.normalizar(facturacion);

    if (factNorm.includes('100k') || factNorm.includes('100000') || 
        factNorm.includes('+100') || factNorm.includes('mas de 100')) {
      score += 40; flags.push('whale'); signals.buy += 3;
    } else if (factNorm.includes('50k') || factNorm.includes('50000') || factNorm.includes('+50')) {
      score += 35; flags.push('high_revenue'); signals.buy += 2;
    } else if (factNorm.includes('20k') || factNorm.includes('30k') || factNorm.includes('40k')) {
      score += 28; flags.push('good_revenue'); signals.buy += 1;
    } else if (factNorm.includes('10k') || factNorm.includes('10000') || factNorm.includes('15k')) {
      score += 22; flags.push('medium_revenue');
    } else if (factNorm.includes('5k') || factNorm.includes('5000')) {
      score += 15; flags.push('starter_revenue');
    } else if (factNorm.includes('2k') || factNorm.includes('3k')) {
      score += 8; flags.push('low_revenue'); signals.risk += 1;
    } else if (factNorm.includes('1k') || factNorm.includes('1000') || factNorm.includes('menos')) {
      score += 3; flags.push('early_stage'); signals.risk += 2;
    }

    // ───────────────────────────────────────────────────────────────────────
    // EQUIPO (25 pts max)
    // ───────────────────────────────────────────────────────────────────────
    const equipoNorm = Utils.normalizar(equipo);

    if (equipoNorm.includes('20') || equipoNorm.includes('30') || equipoNorm.includes('50') ||
        equipoNorm.includes('mas de 10') || equipoNorm.includes('+10')) {
      score += 25; flags.push('large_team'); signals.buy += 2;
    } else if (equipoNorm.includes('10') || equipoNorm.includes('8') || equipoNorm.includes('9')) {
      score += 20; flags.push('growing_team'); signals.buy += 1;
    } else if (equipoNorm.includes('5') || equipoNorm.includes('6') || equipoNorm.includes('7')) {
      score += 15; flags.push('medium_team');
    } else if (equipoNorm.includes('3') || equipoNorm.includes('4')) {
      score += 10; flags.push('small_team');
    } else if (equipoNorm.includes('2')) {
      score += 5; flags.push('duo');
    } else if (equipoNorm.includes('solo') || equipoNorm.includes('1') || equipoNorm.includes('yo')) {
      score += 2; flags.push('solo_founder'); signals.risk += 1;
    }

    // ───────────────────────────────────────────────────────────────────────
    // URGENCIA (20 pts max)
    // ───────────────────────────────────────────────────────────────────────
    const urgNorm = Utils.normalizar(urgencia);

    if (urgNorm.includes('inmediato') || urgNorm.includes('ahora') || urgNorm.includes('ya') ||
        urgNorm.includes('urgente') || urgNorm.includes('asap') || urgNorm.includes('hoy')) {
      score += 20; flags.push('urgent'); signals.buy += 3;
    } else if (urgNorm.includes('esta semana') || urgNorm.includes('7 dias') || urgNorm.includes('pronto')) {
      score += 16; flags.push('very_soon'); signals.buy += 2;
    } else if (urgNorm.includes('15') || urgNorm.includes('2 semanas') || urgNorm.includes('este mes')) {
      score += 12; flags.push('soon'); signals.buy += 1;
    } else if (urgNorm.includes('30') || urgNorm.includes('mes') || urgNorm.includes('proximo mes')) {
      score += 8; flags.push('planned');
    } else if (urgNorm.includes('60') || urgNorm.includes('90') || urgNorm.includes('trimestre')) {
      score += 4; flags.push('exploring'); signals.risk += 1;
    } else if (urgNorm.includes('no') || urgNorm.includes('despues') || urgNorm.includes('luego')) {
      score += 1; flags.push('cold'); signals.risk += 2;
    }

    // ───────────────────────────────────────────────────────────────────────
    // PRESUPUESTO 5K (20 pts max)
    // ───────────────────────────────────────────────────────────────────────
    const presNorm = Utils.normalizar(presupuesto5k);

    if (presNorm.includes('si') || presNorm === 'yes' || presNorm.includes('claro') ||
        presNorm.includes('por supuesto') || presNorm.includes('definitivamente')) {
      score += 20; flags.push('budget_confirmed'); signals.buy += 3;
    } else if (presNorm.includes('posible') || presNorm.includes('probable') || 
               presNorm.includes('creo') || presNorm.includes('tal vez')) {
      score += 10; flags.push('budget_maybe'); signals.opportunity += 1;
    } else if (presNorm.includes('depende') || presNorm.includes('ver') || presNorm.includes('evaluar')) {
      score += 5; flags.push('budget_conditional');
    } else if (presNorm.includes('no') || presNorm.includes('dificil') || presNorm.includes('mucho')) {
      score += 0; flags.push('budget_constraint'); signals.risk += 2;
    }

    // ───────────────────────────────────────────────────────────────────────
    // INVERSIÓN TECH (10 pts max)
    // ───────────────────────────────────────────────────────────────────────
    const techNorm = Utils.normalizar(inversionTech);

    if (techNorm.includes('si') || techNorm.includes('yes') || techNorm.includes('claro')) {
      score += 10; flags.push('tech_ready'); signals.buy += 1;
    } else if (techNorm.includes('algo') || techNorm.includes('poco') || techNorm.includes('basico')) {
      score += 5; flags.push('tech_basic');
    } else if (techNorm.includes('no') || techNorm.includes('nada')) {
      score += 0; flags.push('tech_virgin'); signals.opportunity += 2;
    }

    // ───────────────────────────────────────────────────────────────────────
    // INDUSTRY DETECTION
    // ───────────────────────────────────────────────────────────────────────
    let detectedIndustry = 'general';
    const allText = Utils.normalizar(`${industria} ${infoAdicional} ${dolorPrincipal}`);

    for (const [ind, keywords] of Object.entries(CONFIG.industrias)) {
      if (keywords.some(kw => allText.includes(kw))) {
        detectedIndustry = ind;
        break;
      }
    }

    // ───────────────────────────────────────────────────────────────────────
    // TIER CALCULATION
    // ───────────────────────────────────────────────────────────────────────
    let tier = 'standard';
    if (score >= 90 || (score >= 75 && signals.buy >= 6)) {
      tier = 'vip';
    } else if (score >= 65 || (score >= 50 && signals.buy >= 4)) {
      tier = 'premium';
    } else if (score >= 40 || signals.buy >= 2) {
      tier = 'qualified';
    }

    return {
      score,
      flags,
      signals,
      tier,
      industry: detectedIndustry,
      facturacionRaw: facturacion,
      equipoRaw: equipo
    };
  }
};


