// SECTION 8: DATE FORMATTER
// ═══════════════════════════════════════════════════════════════════════════

const DateFormatter = {

  extractDay(fechaStr) {
    if (!fechaStr) return null;

    try {
      const dias = ['lunes', 'martes', 'miércoles', 'jueves', 'viernes', 'sábado', 'domingo'];
      const fechaLower = fechaStr.toLowerCase();

      for (const dia of dias) {
        if (fechaLower.includes(dia)) {
          const match = fechaStr.match(new RegExp(`${dia}[,\\s]+(\\d{1,2}\\s+de\\s+\\w+)`, 'i'));
          if (match) return Utils.capitalizar(dia) + ' ' + match[1];
          return Utils.capitalizar(dia);
        }
      }

      const fecha = new Date(fechaStr);
      if (!isNaN(fecha.getTime())) {
        return fecha.toLocaleDateString('es-CO', {
          timeZone: 'America/Bogota',
          weekday: 'long',
          day: 'numeric',
          month: 'long'
        });
      }
    } catch (e) {}

    return fechaStr;
  },

  extractTime(fechaStr) {
    if (!fechaStr) return null;

    try {
      const horaMatch = fechaStr.match(/(\d{1,2}:\d{2})\s*(am|pm|a\.m\.|p\.m\.)?/i);
      if (horaMatch) return horaMatch[0];

      const fecha = new Date(fechaStr);
      if (!isNaN(fecha.getTime())) {
        return fecha.toLocaleTimeString('es-CO', {
          timeZone: 'America/Bogota',
          hour: '2-digit',
          minute: '2-digit',
          hour12: true
        });
      }
    } catch (e) {}

    return null;
  }
};


