      'DESCARGAR AHORA',
      'OBTENER ACCESO'
    ],
    qualified: [
      'ACCEDER AL SISTEMA',
      'DESCARGAR',
      'OBTENER ACCESO',
      'DESCARGAR AHORA'
    ],
    standard: [
      'DESCARGAR GRATIS',
      'ACCEDER',
      'DESCARGAR',
      'OBTENER'
    ]
  },

  // ─────────────────────────────────────────────────────────────────────────
  // 9.8 GENERATE FUNCTION
  // ─────────────────────────────────────────────────────────────────────────
  generate(profile) {
    const { tier, painCategoria, flags, facturacion, equipo, intensidad } = profile;
    const isUrgent = flags.includes('urgent') || flags.includes('very_soon');

    const replace = (text) => {
      return text
        .replace(/{facturacion}/g, facturacion || 'tu nivel actual')
        .replace(/{equipo}/g, equipo || 'tu equipo');
    };

    // Select intro
    let intro;
    if (tier === 'vip') {
      const options = this.intros.vip[painCategoria] || this.intros.vip.general;
      intro = replace(Utils.random(options));
    } else if (tier === 'premium') {
      const options = this.intros.premium[painCategoria] || this.intros.premium.general;
      intro = replace(Utils.random(options));
    } else if (tier === 'qualified') {
      const options = this.intros.qualified[painCategoria] || this.intros.qualified.general;
      intro = replace(Utils.random(options));
    } else {
      intro = Utils.random(this.intros.standard);
    }

    // Select pain response
    let painResponse;
    const painTier = tier === 'vip' ? 'vip' : (tier === 'premium' ? 'premium' : 'standard');
    const painOptions = this.painResponses[painCategoria]?.[painTier] || this.painResponses.general;
    painResponse = replace(Utils.random(painOptions));

    // Select closing
    const closingOptions = this.closings[tier] || this.closings.standard;
    const closing = Utils.random(closingOptions);

    // Select PS
    let ps;
    if (tier === 'vip' && isUrgent) {
      ps = replace(Utils.random(this.ps.vip_urgent));
    } else if (tier === 'vip') {
      ps = replace(Utils.random(this.ps.vip_normal));
    } else if (tier === 'premium' && isUrgent) {
      ps = Utils.random(this.ps.premium_urgent);
    } else if (tier === 'premium') {
      ps = Utils.random(this.ps.premium_normal);
    } else if (tier === 'qualified') {
      ps = Utils.random(this.ps.qualified);
    } else {
      ps = Utils.random(this.ps.standard);
    }

    // Select urgency
    const urgencyOptions = this.urgency[tier] || this.urgency.standard;
    const urgencyMessage = Utils.random(urgencyOptions);

    // Select CTA
    const ctaOptions = this.cta[tier] || this.cta.standard;
    const ctaText = Utils.random(ctaOptions);

    return {
      intro,
      painResponse,
      closing,
      ps,
      urgencyMessage,
      ctaText
    };
  },

  // ─────────────────────────────────────────────────────────────────────────
  // 9.9 GENERATE SUBJECT
  // ─────────────────────────────────────────────────────────────────────────
  generateSubject(tier, firstName, hasValidName) {
    const tierSubjects = this.subjects[tier] || this.subjects.standard;
    const options = hasValidName ? tierSubjects.withName : tierSubjects.withoutName;
    let subject = Utils.random(options);

    if (hasValidName && firstName) {
      subject = subject.replace(/{name}/g, firstName);
    }

    return subject;
  }
};


