// 1. Merge data from all sources
const merged = DataMerger.merge(protocolosData, onboardingData, input);

// 2. Extract first name
const firstName = NameProcessor.extract(merged.nombre);
const hasValidName = !!firstName;

// 3. Analyze pain point
const painAnalysis = PainAnalyzer.process(merged.dolorPrincipal);

// 4. Analyze profile
const profileAnalysis = ProfileAnalyzer.analyze({
  facturacion: merged.facturacion,
  equipo: merged.equipo,
  urgencia: merged.urgencia,
  presupuesto5k: merged.presupuesto5k,
  inversionTech: merged.inversionTech,
  dolorPrincipal: merged.dolorPrincipal,
  canal: merged.canal,
  infoAdicional: merged.infoAdicional,
  industria: merged.industria
});

// 5. Format dates
const diaLlamada = DateFormatter.extractDay(merged.fechaEvento);
const horaLlamada = DateFormatter.extractTime(merged.fechaEvento);
const fechaEnvio = Utils.formatDate();

// 6. Generate personalized copy
const copy = CopyEngine.generate({
  tier: profileAnalysis.tier,
  painCategoria: painAnalysis.categoria,
  flags: profileAnalysis.flags,
  facturacion: merged.facturacion,
  equipo: merged.equipo,
  intensidad: painAnalysis.intensidad
});

// 7. Generate subject line
const emailSubject = CopyEngine.generateSubject(
  profileAnalysis.tier,
  firstName,
  hasValidName
);

// 8. Determine VIP status
const isVIP = profileAnalysis.tier === 'vip' || merged.score >= 75;

// 9. Generate HTML
const emailHTML = EmailTemplate.generate({
  firstName,
  hasValidName,
  painPoint: painAnalysis.texto,
  hasValidPainPoint: painAnalysis.hasValid,
  fechaEnvio,
  downloadUrl: DRIVE_FOLDER,
  score: merged.score,
  tier: profileAnalysis.tier,
  calendlyLink: merged.calendlyLink,
  diaLlamada,
  horaLlamada,
  copy,
  isVIP
