    'cheryl', 'hannah', 'jacqueline', 'martha', 'gloria', 'teresa', 'ann',
    'sara', 'madison', 'frances', 'kathryn', 'janice', 'jean', 'abigail',
    'alice', 'judy', 'sophia', 'grace', 'denise', 'amber', 'doris',
    'marilyn', 'danielle', 'beverly', 'isabella', 'theresa', 'diana',
    'natalie', 'brittany', 'charlotte', 'marie', 'kayla', 'alexis', 'lori'
  ],

  // Terminaciones típicas femeninas en español
  terminacionesFem: ['a', 'ela', 'ina', 'ita', 'esa', 'isa', 'ia'],

  // Terminaciones típicas masculinas en español  
  terminacionesMasc: ['o', 'os', 'ón', 'án', 'er', 'or', 'el', 'iel'],

  detect(nombre) {
    if (!nombre || typeof nombre !== 'string') return 'neutral';

    // Extraer primer nombre
    const primerNombre = nombre.trim().split(' ')[0].toLowerCase()
      .normalize('NFD').replace(/[\u0300-\u036f]/g, '');

    if (primerNombre.length < 2) return 'neutral';

    // Verificar en lista de nombres femeninos
    if (this.femeninos.includes(primerNombre)) return 'femenino';

    // Verificar terminaciones
    for (const term of this.terminacionesFem) {
      if (primerNombre.endsWith(term) && primerNombre.length > 3) {
        // Excepciones masculinas que terminan en 'a'
        const excepcionesMasc = ['garcia', 'borja', 'garcia', 'joshua', 'luca', 'nikita'];
        if (!excepcionesMasc.includes(primerNombre)) {
          return 'femenino';
        }
      }
    }

    for (const term of this.terminacionesMasc) {
      if (primerNombre.endsWith(term)) return 'masculino';
    }

    return 'neutral';
  }
};

// ═══════════════════════════════════════════════════════════════════════════
// EXTRACTOR DE NOMBRE
// ═══════════════════════════════════════════════════════════════════════════

function extraerPrimerNombre(nombreCompleto) {
  if (!nombreCompleto || typeof nombreCompleto !== 'string') return null;

  const partes = nombreCompleto.trim().split(' ').filter(p => p.length > 1);
  if (partes.length === 0) return null;

  // Saltar títulos
  const titulos = ['dr', 'dra', 'lic', 'ing', 'sr', 'sra', 'don', 'doña', 'mr', 'mrs', 'ms'];
  let idx = 0;
  if (titulos.includes(partes[0].toLowerCase().replace('.', ''))) {
    idx = 1;
  }

  if (!partes[idx]) return null;

  return partes[idx].charAt(0).toUpperCase() + partes[idx].slice(1).toLowerCase();
}

// ═══════════════════════════════════════════════════════════════════════════
// ANÁLISIS DE RED FLAGS
// ═══════════════════════════════════════════════════════════════════════════

function analizarRedFlags(scoring) {
  const flags = scoring?.redFlags || [];
  const reasons = [];

  if (flags.includes('no_budget')) reasons.push('Sin presupuesto confirmado');
  if (flags.includes('low_revenue')) reasons.push('Facturación muy baja');
  if (flags.includes('no_urgency')) reasons.push('Sin urgencia definida');
  if (flags.includes('vague_pain')) reasons.push('Problema poco claro');
  if (flags.includes('tire_kicker')) reasons.push('Posible curioso');
  if (flags.includes('student')) reasons.push('Perfil estudiante');
  if (flags.includes('job_seeker')) reasons.push('Busca empleo');

  return {
    flags,
    reasons,
    mainReason: reasons[0] || 'No califica en este momento'
  };
}

