const GenderDetector = {

  femeninos: new Set([
    'maria', 'ana', 'carmen', 'laura', 'patricia', 'andrea', 'lucia', 'sofia',
    'isabel', 'rosa', 'elena', 'paula', 'gabriela', 'daniela', 'alejandra',
    'victoria', 'valentina', 'camila', 'mariana', 'carolina', 'fernanda',
    'monica', 'veronica', 'adriana', 'diana', 'claudia', 'sandra', 'silvia',
    'lorena', 'paola', 'natalia', 'marcela', 'cecilia', 'susana', 'martha',
    'gloria', 'teresa', 'julia', 'beatriz', 'rocio', 'cristina', 'alicia',
    'francisca', 'guadalupe', 'leticia', 'norma', 'yolanda', 'karla', 'karen',
    'jessica', 'jennifer', 'stephanie', 'michelle', 'melissa', 'vanessa',
    'viviana', 'ximena', 'jimena', 'regina', 'renata', 'ivanna', 'mary',
    'elizabeth', 'barbara', 'susan', 'sarah', 'nancy', 'lisa', 'ashley',
    'emily', 'amanda', 'rebecca', 'helen', 'rachel', 'catherine', 'megan',
    'hannah', 'olivia', 'sophia', 'grace', 'natalie', 'charlotte', 'emma',
    'madison', 'abigail', 'chloe', 'samantha', 'evelyn', 'lily', 'zoe',
    'mia', 'ella', 'scarlett', 'aurora', 'penelope', 'layla', 'riley'
  ]),

  detect(nombre) {
    if (!nombre || typeof nombre !== 'string') return 'neutral';

    const primer = nombre.trim().split(' ')[0].toLowerCase()
      .normalize('NFD').replace(/[\u0300-\u036f]/g, '');

    if (primer.length < 2) return 'neutral';
    if (this.femeninos.has(primer)) return 'femenino';

    if (primer.endsWith('a') && primer.length > 3) {
      const exc = ['garcia', 'borja', 'joshua', 'luca', 'nikita', 'sasha'];
      if (!exc.includes(primer)) return 'femenino';
    }

    if (['o', 'os', 'er', 'or', 'el', 'an', 'on', 'us'].some(t => primer.endsWith(t))) {
      return 'masculino';
    }

    return 'neutral';
  }
};

