// SECTION 3: UTILIDADES
// ═══════════════════════════════════════════════════════════════════════════

function extraerNombre(nombreCompleto) {
  if (!nombreCompleto || typeof nombreCompleto !== 'string') return null;

  const partes = nombreCompleto.trim().split(' ').filter(p => p.length > 1);
  if (!partes.length) return null;

  const titulos = ['dr', 'dra', 'lic', 'ing', 'sr', 'sra', 'mr', 'mrs', 'ms', 'prof', 'coach'];
  let idx = titulos.includes(partes[0].toLowerCase().replace('.', '')) ? 1 : 0;

  if (!partes[idx]) return null;
  return partes[idx].charAt(0).toUpperCase() + partes[idx].slice(1).toLowerCase();
}

function normalizar(texto) {
  if (!texto) return '';
  return texto.toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function random(arr) {
  return arr[Math.floor(Math.random() * arr.length)];
}

