// SECTION 4: ANALIZADOR DE PERFIL ULTRA
// ═══════════════════════════════════════════════════════════════════════════

const ProfileAnalyzer = {

  // Detectar canal principal
  detectChannel(text) {
    if (!text) return 'general';
    const t = normalizar(text);

    if (t.includes('instagram') || t.includes('ig') || t.includes('insta')) return 'instagram';
    if (t.includes('tiktok') || t.includes('tik tok')) return 'tiktok';
    if (t.includes('youtube') || t.includes('yt')) return 'youtube';
    if (t.includes('linkedin')) return 'linkedin';
    if (t.includes('facebook') || t.includes('fb')) return 'facebook';
    if (t.includes('twitter') || t.includes('x')) return 'twitter';
    if (t.includes('email') || t.includes('correo')) return 'email';
    if (t.includes('whatsapp') || t.includes('wsp')) return 'whatsapp';
    if (t.includes('redes') || t.includes('social')) return 'redes';

    return 'general';
  },

  // Detectar industria
  detectIndustry(text) {
    if (!text) return 'general';
    const t = normalizar(text);

    if (t.includes('coach') || t.includes('mentor') || t.includes('entrenador')) return 'coaching';
    if (t.includes('consultor') || t.includes('asesor') || t.includes('advisory')) return 'consultoria';
    if (t.includes('agencia') || t.includes('agency') || t.includes('marketing')) return 'agencia';
    if (t.includes('saas') || t.includes('software') || t.includes('app') || t.includes('tech')) return 'saas';
    if (t.includes('ecommerce') || t.includes('tienda') || t.includes('productos')) return 'ecommerce';
    if (t.includes('curso') || t.includes('academia') || t.includes('formacion')) return 'educacion';
    if (t.includes('freelance') || t.includes('servicio') || t.includes('profesional')) return 'servicios';

    return 'general';
  },

  // Detectar madurez
  detectMaturity(revenue, teamSize) {
    const rev = normalizar(revenue);
    const team = normalizar(teamSize);

    if (rev.includes('50k') || rev.includes('100k') || rev.includes('+50') || 
        rev.includes('mas de 50') || rev.includes('100')) {
      return 'scaling';
    }

    if (rev.includes('10k') || rev.includes('20k') || rev.includes('30k') || rev.includes('40k') ||
        team.includes('5') || team.includes('6') || team.includes('7') || team.includes('8') ||
        team.includes('10') || team.includes('+')) {
      return 'growing';
    }

    return 'starter';
  },

  // Extraer keywords del dolor
  extractPainKeywords(painText) {
    if (!painText) return [];
    const t = normalizar(painText);

    const allKeywords = [
      // Clientes/Ventas
      'cliente', 'vender', 'ventas', 'lead', 'prospecto', 'cerrar', 'conseguir',
      // Tiempo
      'tiempo', 'horas', 'ocupado', 'saturado', 'manual',
      // Contenido
      'contenido', 'publicar', 'ideas', 'reel', 'historia', 'post', 'viral',
      // Instagram específico
      'instagram', 'seguidores', 'alcance', 'views', 'bio', 'perfil',
      // Automatización
      'automatizar', 'sistema', 'proceso', 'ia', 'inteligencia artificial',
      // Escalabilidad
      'escalar', 'crecer', 'limite', 'tope', 'expandir',
      // Organización
      'caos', 'organizar', 'planificar', 'estructura', 'orden',
      // Equipo
      'equipo', 'delegar', 'solo', 'contratar'
    ];

    return allKeywords.filter(kw => t.includes(kw));
  }
};

