// SECTION 5: SELECTOR DE RECURSO INTELIGENTE
// ═══════════════════════════════════════════════════════════════════════════

function seleccionarRecursos(profile) {
  const { painKeywords, channel, industry, maturity } = profile;

  const scores = RECURSOS.map(recurso => {
    let score = recurso.peso; // Base score

    // Match por keywords de dolor (peso alto)
    const dolorMatches = recurso.dolores.filter(d => 
      painKeywords.some(pk => d.includes(pk) || pk.includes(d))
    ).length;
    score += dolorMatches * 15;

    // Match por canal
    if (recurso.canales.includes('all') || recurso.canales.includes(channel)) {
      score += 10;
    }

    // Match por industria
    if (recurso.industrias.includes('all') || recurso.industrias.includes(industry)) {
      score += 8;
    }

    // Match por madurez
    if (recurso.madurez.includes(maturity)) {
      score += 5;
    }

    return { recurso, score };
  });

  // Ordenar por score
  scores.sort((a, b) => b.score - a.score);

  // Retornar top 3
  return {
    principal: scores[0],
    secundario: scores[1],
    terciario: scores[2]
  };
}

