  titulos: new Set(['dr','dra','doctor','doctora','lic','licdo','licda','licenciado','licenciada','ing','ingeniero','ingeniera','arq','arquitecto','arquitecta','abog','abogado','abogada','prof','profesor','profesora','sr','sra','srta','señor','señora','señorita','mr','mrs','ms','miss','coach','mtr','mtro','mtra','maestro','maestra','phd','md','mba','cpa']),
  particulas: new Set(['de','del','la','las','los','van','von','der','den','di','da','dos','mac','mc']),
  extraer(name) {
    if (!name || typeof name !== 'string') return { firstName: null, hasTitulo: false };
    const parts = name.trim().replace(/\s+/g,' ').replace(/[.,;:]/g,'').toLowerCase().split(' ').filter(p=>p.length>0);
    if (!parts.length) return { firstName: null, hasTitulo: false };
    let i = 0, hasTitulo = false;
    while (i < parts.length && this.titulos.has(parts[i].replace(/\./g,''))) { hasTitulo = true; i++; }
    if (i >= parts.length) i = parts.length - 1;
    while (i < parts.length - 1 && this.particulas.has(parts[i])) i++;
    const first = parts[i];
    return first ? { firstName: first.charAt(0).toUpperCase() + first.slice(1), hasTitulo } : { firstName: null, hasTitulo };
  }
};

