// ═══════════════════════════════════════════════════════════════════════════════
// PARSER DE ICS - Busca el link REAL de Meet
// ═══════════════════════════════════════════════════════════════════════════════

function extractMeetLinkFromICS(ics) {
  if (!ics || typeof ics !== 'string') return null;

  // Limpiar y normalizar
  const content = ics
    .replace(/\r\n[ \t]/g, '')  // Unfold
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n');

  let meetLink = null;
  let conferenceType = null;

  // ═══════════════════════════════════════════════════════════════════
  // MÉTODO 1: X-GOOGLE-CONFERENCE (el más confiable para Google Meet)
  // ═══════════════════════════════════════════════════════════════════
  const googleConfMatch = content.match(/X-GOOGLE-CONFERENCE:(https:\/\/meet\.google\.com\/[a-z]{3}-[a-z]{4}-[a-z]{3})/i);
  if (googleConfMatch) {
    meetLink = googleConfMatch[1];
    conferenceType = 'google_meet';
  }

  // ═══════════════════════════════════════════════════════════════════
  // MÉTODO 2: Buscar en LOCATION
  // ═══════════════════════════════════════════════════════════════════
  if (!meetLink) {
    const locationMatch = content.match(/LOCATION[^:]*:(.*?)(?:\n|$)/i);
    if (locationMatch) {
      const location = locationMatch[1];
      const meetInLocation = location.match(/https:\/\/meet\.google\.com\/[a-z]{3}-[a-z]{4}-[a-z]{3}/i);
      if (meetInLocation) {
        meetLink = meetInLocation[0];
        conferenceType = 'google_meet';
      }
    }
  }

  // ═══════════════════════════════════════════════════════════════════
  // MÉTODO 3: Buscar en DESCRIPTION
  // ═══════════════════════════════════════════════════════════════════
  if (!meetLink) {
    // Google Meet
    const meetMatch = content.match(/https:\/\/meet\.google\.com\/[a-z]{3}-[a-z]{4}-[a-z]{3}/gi);
    if (meetMatch) {
      meetLink = meetMatch[0];
      conferenceType = 'google_meet';
    }
  }

  // ═══════════════════════════════════════════════════════════════════
  // MÉTODO 4: Zoom
  // ═══════════════════════════════════════════════════════════════════
  if (!meetLink) {
    const zoomMatch = content.match(/https:\/\/[a-z0-9.-]*zoom\.us\/j\/[\d]+(?:\?pwd=[a-zA-Z0-9]+)?/gi);
    if (zoomMatch) {
      meetLink = zoomMatch[0];
      conferenceType = 'zoom';
    }
  }

  // ═══════════════════════════════════════════════════════════════════
  // MÉTODO 5: Teams
  // ═══════════════════════════════════════════════════════════════════
  if (!meetLink) {
    const teamsMatch = content.match(/https:\/\/teams\.microsoft\.com\/l\/meetup-join\/[^\s\\"<>]+/gi);
    if (teamsMatch) {
      meetLink = teamsMatch[0];
      conferenceType = 'teams';
    }
  }

  // Limpiar el link final
  if (meetLink) {
    meetLink = meetLink
      .replace(/\\n/g, '')
      .replace(/\\r/g, '')
      .replace(/\\$/g, '')
      .replace(/[\]\["'<>{}]+$/g, '')
      .trim();
  }

  return { meetLink, conferenceType };
}

// Extraer información adicional del ICS
function extractICSMetadata(ics) {
  const metadata = {
    summary: null,
    organizer: null,
    attendees: []
  };

  if (!ics) return metadata;

  const summaryMatch = ics.match(/SUMMARY[^:]*:(.+?)(?:\n|$)/i);
  if (summaryMatch) metadata.summary = summaryMatch[1].trim();

  const organizerMatch = ics.match(/ORGANIZER[^:]*:mailto:([^\s:]+)/i);
  if (organizerMatch) metadata.organizer = organizerMatch[1];

  return metadata;
}

